 :root {
   color-scheme: dark;
-  /* Use the Next.js font variable we injected, falling back to system serifs */
+
+  /* ========================================
+     FONT STACKS
+     ======================================== */
   --font-serif-stack: var(--font-serif), "Charter", "Georgia", "Cambria", "Times New Roman", serif;
   --font-sans: var(--font-inter), system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
+
+  /* ========================================
+     TYPOGRAPHY SCALE (Fluid & Responsive)
+     Using clamp() for smooth scaling
+     ======================================== */
+  --type-hero: clamp(2.5rem, 8vw, 6rem);           /* 40px → 96px */
+  --type-h1: clamp(2rem, 5vw, 3.75rem);            /* 32px → 60px */
+  --type-h2: clamp(1.5rem, 4vw, 2.5rem);           /* 24px → 40px */
+  --type-h3: clamp(1.25rem, 3vw, 1.875rem);        /* 20px → 30px */
+  --type-h4: clamp(1.125rem, 2vw, 1.5rem);         /* 18px → 24px */
+  --type-body-lg: clamp(1rem, 1.5vw, 1.25rem);     /* 16px → 20px */
+  --type-body: 1rem;                               /* 16px */
+  --type-body-sm: 0.875rem;                        /* 14px */
+  --type-caption: 0.75rem;                         /* 12px - MINIMUM */
+
+  /* Line Heights */
+  --leading-none: 1;
+  --leading-tight: 1.2;
+  --leading-snug: 1.375;
+  --leading-normal: 1.5;
+  --leading-relaxed: 1.625;
+  --leading-loose: 1.75;
+
+  /* Letter Spacing */
+  --tracking-tighter: -0.04em;
+  --tracking-tight: -0.02em;
+  --tracking-normal: 0;
+  --tracking-wide: 0.025em;
+  --tracking-wider: 0.05em;
+  --tracking-widest: 0.1em;
+
+  /* ========================================
+     SPACING SCALE (8px base rhythm)
+     ======================================== */
+  --space-0: 0;
+  --space-1: 0.25rem;   /* 4px */
+  --space-2: 0.5rem;    /* 8px */
+  --space-3: 0.75rem;   /* 12px */
+  --space-4: 1rem;      /* 16px */
+  --space-5: 1.25rem;   /* 20px */
+  --space-6: 1.5rem;    /* 24px */
+  --space-8: 2rem;      /* 32px */
+  --space-10: 2.5rem;   /* 40px */
+  --space-12: 3rem;     /* 48px */
+  --space-16: 4rem;     /* 64px */
+  --space-20: 5rem;     /* 80px */
+  --space-24: 6rem;     /* 96px */
+  --space-32: 8rem;     /* 128px */
+
+  /* Section Spacing (Responsive) */
+  --section-py: clamp(4rem, 10vw, 7rem);           /* 64px → 112px */
+  --section-px: clamp(1rem, 5vw, 2rem);            /* 16px → 32px */
+
+  /* ========================================
+     ELEVATION/SHADOW SCALE
+     ======================================== */
+  --shadow-xs: 0 1px 2px 0 rgb(0 0 0 / 0.05);
+  --shadow-sm: 0 1px 3px 0 rgb(0 0 0 / 0.1), 0 1px 2px -1px rgb(0 0 0 / 0.1);
+  --shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1);
+  --shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1);
+  --shadow-xl: 0 20px 25px -5px rgb(0 0 0 / 0.1), 0 8px 10px -6px rgb(0 0 0 / 0.1);
+  --shadow-2xl: 0 25px 50px -12px rgb(0 0 0 / 0.25);
+
+  /* Glow Shadows (for dark theme) */
+  --glow-sm: 0 0 10px -3px;
+  --glow-md: 0 0 20px -5px;
+  --glow-lg: 0 0 30px -5px;
+
+  /* ========================================
+     EASING FUNCTIONS (Stripe-level polish)
+     ======================================== */
+  --ease-out: cubic-bezier(0.33, 1, 0.68, 1);
+  --ease-in-out: cubic-bezier(0.65, 0, 0.35, 1);
+  --ease-spring: cubic-bezier(0.34, 1.56, 0.64, 1);
+  --ease-bounce: cubic-bezier(0.68, -0.6, 0.32, 1.6);
+  --ease-smooth: cubic-bezier(0.25, 0.46, 0.45, 0.94);
+
+  /* Animation Durations */
+  --duration-instant: 0.1s;
+  --duration-fast: 0.15s;
+  --duration-normal: 0.25s;
+  --duration-slow: 0.4s;
+  --duration-slower: 0.6s;
+
+  /* ========================================
+     BORDER RADIUS SCALE
+     ======================================== */
+  --radius-sm: 0.375rem;   /* 6px - buttons, inputs */
+  --radius-md: 0.5rem;     /* 8px - small cards */
+  --radius-lg: 0.75rem;    /* 12px - cards */
+  --radius-xl: 1rem;       /* 16px - large cards */
+  --radius-2xl: 1.5rem;    /* 24px - hero cards */
+  --radius-full: 9999px;   /* pills, avatars */
+
+  /* ========================================
+     BRAND GRADIENTS
+     ======================================== */
+  --gradient-hero: linear-gradient(135deg, #38bdf8 0%, #a78bfa 50%, #34d399 100%);
+  --gradient-primary: linear-gradient(135deg, #8b5cf6 0%, #d946ef 100%);
+  --gradient-secondary: linear-gradient(135deg, #38bdf8 0%, #6366f1 100%);
+  --gradient-accent: linear-gradient(135deg, #f59e0b 0%, #ef4444 100%);
+  --gradient-success: linear-gradient(135deg, #10b981 0%, #34d399 100%);
+
+  /* Glass Effect */
+  --glass-bg: rgba(15, 23, 42, 0.5);
+  --glass-border: rgba(255, 255, 255, 0.1);
+  --glass-blur: 12px;
+
+  /* ========================================
+     TOUCH TARGET MINIMUM
+     ======================================== */
+  --touch-target-min: 44px;
 }

